async def retire_template(db, template_id):
    # ... retirement logic ...

    # Determine notification message
    affected_sequences = []

    for mapping in template.sequence_mappings:
        if mapping.removed_at:
            continue  # Already removed

        sequence = mapping.sequence

        # Check if this affects current or next week
        current_pos = sequence.current_week_index
        next_pos = (current_pos + 1) % total_active_templates

        if mapping.position == next_pos:
            affected_sequences.append({
                'sequence': sequence,
                'impact': 'next_week',
                'new_next_template': find_new_next_template(sequence, mappings)
            })
        elif mapping.position == current_pos:
            affected_sequences.append({
                'sequence': sequence,
                'impact': 'current_week'
            })
        else:
            affected_sequences.append({
                'sequence': sequence,
                'impact': 'other'
            })

    return affected_sequences

# In retire_template endpoint:
async def send_retirement_notification(template, affected_sequences):
    bot = get_bot()

    for item in affected_sequences:
        seq = item['sequence']

        if item['impact'] == 'next_week':
            message = f"📅 **{template.name} has been removed from {seq.name}**\n\nNext week will now be: {item['new_next_template'].name}"
        elif item['impact'] == 'current_week':
            message = f"👋 **{template.name} has been retired from {seq.name}**\n\nThe current week continues, but this template won't appear again."
        else:
            message = f"🗑️ **{template.name} has been retired!**\n\nGoodbye, {template.name}!"

        try:
            await bot.send_message(message)
        except Exception as e:
            logger.error(f'Discord notification failed: {e}')
